PointUtil = {}

function PointUtil:newPoint(x, y)
    local point = {}
    point.x = x
    point.y = y
    return point
end

function PointUtil:pointEqual(point1, point2)
    return point1.x == point2.x and point1.y == point2.y
end

function PointUtil:pointInRect(point, minX, maxX, minZ, maxZ)
    return (point.x >= minX and point.x <= maxX) and (point.y >= minZ and point.y <= maxZ)
end

function PointUtil:isTableHavePoint(tb, point)
    if tb == nil then
        return false
    end

    for _, val in pairs(tb) do
        if PointUtil:pointEqual(val, point) then
            return true
        end
    end

    return false
end

return PointUtil